  1→import React, { useState, useMemo, useEffect } from 'react';
  2→import { Radar, TrendingUp, ArrowRight, Play, Settings, Target, Trophy, Clock, ArrowUp, ArrowDown, Minus } from 'lucide-react';
  3→import type { User } from '../../types';
  4→import type { CitationCheck, CitationRate, AIEngineId } from '../../types/v3-types';
  5→import { getCitationChecks, getTrackedQueries, getProjectConfig } from '../../services/v3/citation-storage';
  6→import { aggregateCitationRates } from '../../services/v3/citation-checker';
  7→import { runCitationChecks } from '../../services/v3/citation-checker';
  8→import ScoreRing from '../../components/ScoreRing';
  9→
 10→interface Props {
 11→  onBack: () => void;
 12→  user: User | null;
 13→  onNavigate: (view: string) => void;
 14→}
 15→
 16→const ENGINE_META: Record<AIEngineId, { name: string; icon: string; color: string; bgClass: string; textClass: string }> = {
 17→  chatgpt: { name: 'ChatGPT', icon: '🟢', color: '#10a37f', bgClass: 'bg-emerald-500/10', textClass: 'text-emerald-400' },
 18→  perplexity: { name: 'Perplexity', icon: '🔵', color: '#20b8cd', bgClass: 'bg-cyan-500/10', textClass: 'text-cyan-400' },
 19→  gemini: { name: 'Gemini', icon: '🟣', color: '#8b5cf6', bgClass: 'bg-violet-500/10', textClass: 'text-violet-400' },
 20→};
 21→
 22→const CitationDashboardPage: React.FC<Props> = ({ onBack, user, onNavigate }) => {
 23→  const [isRunning, setIsRunning] = useState(false);
 24→  const [progress, setProgress] = useState({ current: 0, total: 0 });
 25→
 26→  const projectId = user?.id || 'default';
 27→  const checks = useMemo(() => getCitationChecks(projectId), [projectId]);
 28→  const queries = useMemo(() => getTrackedQueries(projectId), [projectId]);
 29→  const config = useMemo(() => getProjectConfig(projectId), [projectId]);
 30→
 31→  // Taux de citation agrégés
 32→  const citationRates = useMemo(() => {
 33→    if (checks.length === 0) return null;
 34→    return aggregateCitationRates(checks);
 35→  }, [checks]);
 36→
 37→  // Score de visibilité IA global
 38→  const visibilityScore = useMemo(() => {
 39→    if (!citationRates) return 0;
 40→    const engines: AIEngineId[] = ['chatgpt', 'perplexity', 'gemini'];
 41→    const rates = engines.map(e => citationRates[e]?.citationRatePercent || 0);
 42→    return Math.round(rates.reduce((a, b) => a + b, 0) / rates.length);
 43→  }, [citationRates]);
 44→
 45→  // Dernières 10 citations
 46→  const recentCitations = useMemo(() => {
 47→    return checks
 48→      .filter(c => c.detection.urlExactMatch || c.detection.brandExactMatch || c.detection.urlInSource)
 49→      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
 50→      .slice(0, 10);
 51→  }, [checks]);
 52→
 53→  const handleRunVerification = async () => {
 54→    if (queries.length === 0 || !config) return;
 55→    setIsRunning(true);
 56→    setProgress({ current: 0, total: 1 });
 57→
 58→    try {
 59→      await runCitationChecks(
 60→        queries.filter(q => q.isActive),
 61→        {
 62→          projectId,
 63→          clientUrl: config.clientUrl,
 64→          clientBrand: config.clientBrand,
 65→          brandVariants: config.brandVariants,
 66→          productKeywords: config.productKeywords,
 67→          competitors: [],
 68→        },
 69→        (current, total) => setProgress({ current, total })
 70→      );
 71→      // Reload - force re-render
 72→      window.location.reload();
 73→    } catch (error) {
 74→      console.error('Erreur vérification:', error);
 75→    } finally {
 76→      setIsRunning(false);
 77→    }
 78→  };
 79→
 80→  const getConfidenceBadge = (confidence: 'high' | 'medium' | 'low') => {
 81→    switch (confidence) {
 82→      case 'high': return { label: 'Élevée', class: 'bg-green-500/20 text-green-400' };
 83→      case 'medium': return { label: 'Moyenne', class: 'bg-yellow-500/20 text-yellow-400' };
 84→      case 'low': return { label: 'Faible', class: 'bg-red-500/20 text-red-400' };
 85→    }
 86→  };
 87→
 88→  const getTrendIcon = (trend: string) => {
 89→    if (trend === 'improving') return <ArrowUp size={12} className="text-green-400" />;
 90→    if (trend === 'declining') return <ArrowDown size={12} className="text-red-400" />;
 91→    return <Minus size={12} className="text-gray-500" />;
 92→  };
 93→
 94→  return (
 95→    <div className="w-full px-4 py-10 animate-in fade-in duration-500 pb-24">
 96→      {/* Header */}
 97→      <div className="mb-8">
 98→        <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
 99→          <div className="w-10 h-10 rounded-2xl bg-cyan-500/20 flex items-center justify-center border border-cyan-500/30">
100→            <Radar size={24} className="text-cyan-400" />
101→          </div>
102→          Vos citations dans les moteurs IA
103→        </h1>
104→        <p className="text-gray-500">
105→          Mesurez votre présence réelle dans les réponses de ChatGPT, Perplexity et Gemini.
106→        </p>
107→      </div>
108→
109→      {/* Zone 1 : Score de visibilité IA */}
110→      <div className="grid grid-cols-1 md:grid-cols-12 gap-6 mb-8">
111→        <div className="md:col-span-4 ninja-card p-8 rounded-2xl flex flex-col items-center justify-center relative overflow-hidden border-cyan-500/20">
112→          <div className="absolute top-0 right-0 w-32 h-32 bg-cyan-500/10 blur-3xl rounded-full pointer-events-none" />
113→          <h3 className="text-gray-500 text-sm font-medium uppercase tracking-wider mb-6">Score de Visibilité IA</h3>
114→          <ScoreRing score={visibilityScore} size={160} strokeWidth={12} />
115→          <p className="text-xs text-gray-500 mt-4 text-center">
116→            Basé sur {checks.length} vérification{checks.length > 1 ? 's' : ''}
117→          </p>
118→        </div>
119→
120→        {/* Zone 2 : Taux de citation par moteur */}
121→        <div className="md:col-span-8 ninja-card p-6 rounded-2xl border border-white/[0.08]">
122→          <h3 className="text-sm font-bold text-white mb-6 flex items-center gap-2">
123→            <Target size={16} className="text-cyan-400" />
124→            Taux de citation par moteur IA
125→          </h3>
126→
127→          {citationRates ? (
128→            <div className="space-y-5">
129→              {(['chatgpt', 'perplexity', 'gemini'] as AIEngineId[]).map(engineId => {
130→                const rate = citationRates[engineId];
131→                const meta = ENGINE_META[engineId];
132→                const confidence = getConfidenceBadge(rate.confidence);
133→                return (
134→                  <div key={engineId}>
135→                    <div className="flex items-center justify-between mb-2">
136→                      <div className="flex items-center gap-2">
137→                        <span className="text-lg">{meta.icon}</span>
138→                        <span className="text-sm font-medium text-white">{meta.name}</span>
139→                      </div>
140→                      <div className="flex items-center gap-3">
141→                        <span className="text-sm font-bold text-white">{rate.citationRatePercent}%</span>
142→                        <span className={`text-[10px] px-2 py-0.5 rounded-full font-medium ${confidence.class}`}>
143→                          Confiance: {confidence.label}
144→                        </span>
145→                        {getTrendIcon(rate.trend)}
146→                      </div>
147→                    </div>
148→                    <div className="w-full h-2.5 bg-white/10 rounded-full overflow-hidden">
149→                      <div
150→                        className="h-full rounded-full transition-all duration-700 ease-out"
151→                        style={{ width: `${rate.citationRatePercent}%`, backgroundColor: meta.color }}
152→                      />
153→                    </div>
154→                    <div className="flex justify-between mt-1">
155→                      <span className="text-[10px] text-gray-600">{rate.citationsDetected}/{rate.totalChecks} détections</span>
156→                      <span className="text-[10px] text-gray-600">Score moyen: {rate.avgCitationScore}</span>
157→                    </div>
158→                  </div>
159→                );
160→              })}
161→            </div>
162→          ) : (
163→            <div className="flex flex-col items-center justify-center py-8 text-center">
164→              <Radar size={40} className="text-gray-600 mb-3" />
165→              <p className="text-sm text-gray-500 mb-1">Aucune donnée de citation disponible</p>
166→              <p className="text-xs text-gray-600">Configurez vos requêtes cibles et lancez une vérification.</p>
167→            </div>
168→          )}
169→        </div>
170→      </div>
171→
172→      {/* Zone 4 : Dernières détections */}
173→      <div className="ninja-card rounded-2xl border border-white/[0.08] mb-8 overflow-hidden">
174→        <div className="p-6 border-b border-white/[0.08] flex justify-between items-center bg-white/[0.04]">
175→          <h3 className="font-bold text-white flex items-center gap-2">
176→            <Clock size={18} className="text-gray-500" />
177→            Dernières citations détectées
178→          </h3>
179→          <span className="text-xs text-gray-500">{recentCitations.length} résultat{recentCitations.length > 1 ? 's' : ''}</span>
180→        </div>
181→
182→        {recentCitations.length > 0 ? (
183→          <div className="divide-y divide-white/5">
184→            {recentCitations.map((check) => {
185→              const meta = ENGINE_META[check.engine];
186→              return (
187→                <div key={check.id} className="px-6 py-4 hover:bg-white/[0.02] transition-colors">
188→                  <div className="flex items-start gap-3">
189→                    <span className={`text-xs font-medium px-2 py-1 rounded-full ${meta.bgClass} ${meta.textClass} shrink-0 mt-0.5`}>
190→                      {meta.icon} {meta.name}
191→                    </span>
192→                    <div className="flex-1 min-w-0">
193→                      <p className="text-sm text-white truncate">&quot;{check.promptSent}&quot;</p>
194→                      <div className="flex items-center gap-3 mt-1">
195→                        <span className="text-xs text-gray-500">
196→                          Score: <span className="text-white font-medium">{check.detection.citationScore}</span>
197→                        </span>
198→                        <span className="text-xs text-gray-600">
199→                          {check.detection.positionInResponse === 'first_paragraph' ? 'Premier paragraphe' :
200→                           check.detection.positionInResponse === 'middle' ? 'Milieu de réponse' :
201→                           check.detection.positionInResponse === 'end' ? 'Fin de réponse' : 'Footnote'}
202→                        </span>
203→                        <span className={`text-xs ${
204→                          check.detection.sentiment === 'positive' ? 'text-green-400' :
205→                          check.detection.sentiment === 'negative' ? 'text-red-400' : 'text-gray-500'
206→                        }`}>
207→                          {check.detection.sentiment === 'positive' ? '👍 Positif' :
208→                           check.detection.sentiment === 'negative' ? '👎 Négatif' : '🔘 Neutre'}
209→                        </span>
210→                      </div>
211→                    </div>
212→                    <span className="text-[10px] text-gray-600 shrink-0">
213→                      {new Date(check.createdAt).toLocaleDateString()}
214→                    </span>
215→                  </div>
216→                </div>
217→              );
218→            })}
219→          </div>
220→        ) : (
221→          <div className="px-6 py-10 text-center text-gray-500 text-sm">
222→            Aucune citation détectée pour le moment. Lancez une vérification pour commencer.
223→          </div>
224→        )}
225→      </div>
226→
227→      {/* Zone 5 : Actions */}
228→      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
229→        <button
230→          onClick={handleRunVerification}
231→          disabled={isRunning || queries.length === 0}
232→          className="ninja-card p-5 rounded-2xl border border-cyan-500/20 hover:border-cyan-500/40 transition-all flex items-center gap-4 group disabled:opacity-50 disabled:cursor-not-allowed"
233→        >
234→          <div className="w-10 h-10 rounded-full bg-cyan-500/20 flex items-center justify-center text-cyan-400 group-hover:scale-110 transition-transform">
235→            <Play size={18} />
236→          </div>
237→          <div className="text-left">
238→            <p className="text-sm font-bold text-white">
239→              {isRunning ? `Vérification en cours (${progress.current}/${progress.total})` : 'Lancer une vérification'}
240→            </p>
241→            <p className="text-xs text-gray-500">
242→              {queries.filter(q => q.isActive).length} requêtes actives
243→            </p>
244→          </div>
245→        </button>
246→
247→        <button
248→          onClick={() => onNavigate('tracked-queries')}
249→          className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-purple-500/30 transition-all flex items-center gap-4 group"
250→        >
251→          <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-400 group-hover:scale-110 transition-transform">
252→            <Target size={18} />
253→          </div>
254→          <div className="text-left">
255→            <p className="text-sm font-bold text-white">Gérer les requêtes</p>
256→            <p className="text-xs text-gray-500">{queries.length} requêtes configurées</p>
257→          </div>
258→        </button>
259→
260→        <button
261→          onClick={() => onNavigate('benchmark')}
262→          className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-yellow-500/30 transition-all flex items-center gap-4 group"
263→        >
264→          <div className="w-10 h-10 rounded-full bg-yellow-500/20 flex items-center justify-center text-yellow-400 group-hover:scale-110 transition-transform">
265→            <Trophy size={18} />
266→          </div>
267→          <div className="text-left">
268→            <p className="text-sm font-bold text-white">Voir le benchmark</p>
269→            <p className="text-xs text-gray-500">Comparatif concurrentiel</p>
270→          </div>
271→        </button>
272→      </div>
273→    </div>
274→  );
275→};
276→
277→export default CitationDashboardPage;
